-- HSL team members seed (from 'Hogan Smith Team Members Rate and Bonus - Hogan Agents Pay Plan.csv')
-- Run in Supabase SQL editor. Idempotent: re-running updates existing rows.

CREATE TABLE IF NOT EXISTS public.hsl_team_members (
  email         text PRIMARY KEY,
  full_name     text,
  hsl_name      text,        -- the nickname column from the sheet
  role_raw      text,        -- original 'Department/ Role' string from CSV
  dept_key      text,        -- one of the HSL_DEPT_KEYS, NULL if outside the 13 KPI depts
  is_manager    boolean      NOT NULL DEFAULT false,
  hourly_rate   numeric(10,2),
  ot_rate       numeric(10,2),
  created_at    timestamptz  NOT NULL DEFAULT now(),
  updated_at    timestamptz  NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS hsl_team_members_dept_idx ON public.hsl_team_members(dept_key);

